                                results.append(stdout)
                        except Exception as e:
                            results.append(f"Error executing {file_path}: {e}")
                    else:
                        results.append(file_path)
    except FileNotFoundError:
        results.append(f"Error: Directory not found: {dir_path}")
    except Exception as e:
        results.append(f"An unexpected error occurred: {e}")
    return results

import re
import os
import subprocess
def task_func(dir_path, exe_pattern, execute_files=True):
    pattern = re.compile(exe_pattern)
    results = []

    if not os.path.isdir(dir_path):
        raise ValueError(f"The specified directory '{dir_path}' does not exist.")

    for root, _, files in os.walk(dir_path):
        for file_name in files:
            file_path = os.path.join(root, file_name)

            if pattern.match(file_name) and os.access(file_path, os.X_OK):
                if execute_files:
                    try:
                        result = subprocess.run(
                            [file_path],
                            stdout=subprocess.PIPE,
                            stderr=subprocess.PIPE,
                            text=True
                        )
                        results.append(result.stdout.strip())
                    except Exception as e:
                        results.append(f"Error executing {file_path}: {e}")
                else:
                    results.append(file_path)

    return results

