ARCHIVE_DIR = '/tmp/archive'
def task_func(pattern):
    os.makedirs(ARCHIVE_DIR, exist_ok=True)

    matching_files = glob.glob(pattern)
    if not matching_files:
        raise FileNotFoundError(f"No files found matching the pattern: {pattern}")

    archive_file = os.path.join(ARCHIVE_DIR, 'archive.tar.gz')

    try:
        subprocess.run(['tar', '-czf', archive_file, *matching_files], check=True)
    except subprocess.CalledProcessError as e:
        raise RuntimeError(f"Failed to create archive: {e}")

    for file in matching_files:
        try:
            os.remove(file)
