import numpy as np
from collections import defaultdict
import json
import csv
def task_func(input_file, output_file):
    data = []
    try:
        with open(input_file, 'r') as f:
            data = json.load(f)
    except FileNotFoundError:
        print(f"Error: Input file not found: {input_file}")
        return {}
    except json.JSONDecodeError:
        print(f"Error: Invalid JSON format in file: {input_file}")
        return {}

    if not isinstance(data, list):
        print(f"Error: Input JSON should contain a list of dictionaries: {input_file}")
        return {}

    if not data:
        print(f"Warning: Input JSON list is empty: {input_file}")
        return {}

    field_values = defaultdict(list)
    for item in data:
        if not isinstance(item, dict):
            print(f"Error: Input JSON list should contain only dictionaries: {input_file}")
            return {}
        for key, value in item.items():
            if isinstance(value, (int, float)):
                field_values[key].append(value)
            else:
                print(f"Warning: Skipping non-numeric value for key '{key}': {value}")

    results = {}
    for key, values in field_values.items():
        if values:
            mean_val = np.mean(values)
            median_val = np.median(values)
            results[key] = {"mean": mean_val, "median": median_val}
        else:
            results[key] = {"mean": None, "median": None}

    try:
        with open(output_file, 'w', newline='') as csvfile:
            writer = csv.writer(csvfile)
            writer.writerow(["field", "mean", "median"])
            for key, stats in results.items():
                writer.writerow([key, stats["mean"], stats["median"]])
    except Exception as e:
        print(f"Error writing to CSV file: {output_file}, {e}")
        return {}

    return results

